                                        __ce_slot = __ce_s;
                                        if (__ce_uop.src1_en && __ce_uop.src1_busy) begin
                                            __ce_preg8 = __ce_uop.src1_preg;
                                            if (__ce_preg8 < 160) begin
                                                __ce_q.wake_matrix_src1[__ce_preg8 * __ce_q.wake_words_per_row + (__ce_slot >> 6)] =
                                                    __ce_q.wake_matrix_src1[__ce_preg8 * __ce_q.wake_words_per_row + (__ce_slot >> 6)] |
                                                    (64'b1 << (__ce_slot & 6'h3f));
                                            end
                                        end
