                                            __ce_preg8 = __ce_uop.src2_preg;
                                            if (__ce_preg8 < 160) begin
                                                __ce_q.wake_matrix_src2[__ce_preg8 * __ce_q.wake_words_per_row + (__ce_slot >> 6)] =
                                                    __ce_q.wake_matrix_src2[__ce_preg8 * __ce_q.wake_words_per_row + (__ce_slot >> 6)] |
                                                    (64'b1 << (__ce_slot & 6'h3f));
                                            end
                                        end
                                        __ce_done = 1;
                                    end
                                end
                            end
                        end
                    end
                end
            end
