    // ---- comb_flush ----
    begin : comb_flush
        integer __cf_qi, __cf_i, __cf_j;
        logic [63:0] __cf_clear;
        logic [63:0] __cf_slot_bit;
        logic [63:0] __cf_clear_bits;
        logic [7:0] __cf_preg8;
        integer __cf_word;
        integer __cf_surv;
        LatencyEntry_t __cf_lpe;
        LatencyEntry_t __cf_lpe_arr [0:17];
        IssueQueue_t __cf_q;
        IqStoredEntry_t __cf_e;
        logic __cf_match;
        
        __cf_clear = in_dec_bcast.clear_mask;
        
        if (in_rob_bcast.flush) begin
            // Flush all IQs
            for (__cf_qi = 0; __cf_qi < 5; __cf_qi++) begin
                __cf_q = iqs[__cf_qi];
                for (__cf_i = 0; __cf_i < 64; __cf_i++) begin
                    if (__cf_i < __cf_q.size) begin
                        __cf_q.entry_1[__cf_i].valid = 1'b0;
                    end
                end
                __cf_q.count_1 = 32'h0;
                for (__cf_i = 0; __cf_i < 160; __cf_i++) begin
                    __cf_q.wake_matrix_src1[__cf_i] = 64'h0;
                    __cf_q.wake_matrix_src2[__cf_i] = 64'h0;
                end
                iqs[__cf_qi] = __cf_q;
            end
            // Flush latency_pipe
            for (__cf_i = 0; __cf_i < 18; __cf_i++) begin
                latency_pipe[__cf_i].valid     = 1'b0;
                latency_pipe[__cf_i].countdown = 32'h0;
                latency_pipe[__cf_i].dest_preg = 32'h0;
                latency_pipe[__cf_i].br_mask   = 64'h0;
                latency_pipe[__cf_i].rob_idx   = 32'h0;
                latency_pipe[__cf_i].rob_flag  = 32'h0;
            end
            // Flush latency_pipe_1
            for (__cf_i = 0; __cf_i < 18; __cf_i++) begin
                latency_pipe_1[__cf_i].valid     = 1'b0;
                latency_pipe_1[__cf_i].countdown = 32'h0;
                latency_pipe_1[__cf_i].dest_preg = 32'h0;
                latency_pipe_1[__cf_i].br_mask   = 64'h0;
                latency_pipe_1[__cf_i].rob_idx   = 32'h0;
                latency_pipe_1[__cf_i].rob_flag  = 32'h0;
            end
        end else if (in_dec_bcast.mispred) begin
            // Flush branch-matching entries from IQs
            for (__cf_qi = 0; __cf_qi < 5; __cf_qi++) begin
                __cf_q = iqs[__cf_qi];
                for (__cf_i = 0; __cf_i < 64; __cf_i++) begin
                    if (__cf_i < __cf_q.size) begin
                        __cf_e = __cf_q.entry_1[__cf_i];
                        if (__cf_e.valid) begin
                            __cf_match = ((__cf_e.uop.br_mask & in_dec_bcast.br_mask) != 64'b0);
                            if (__cf_match) begin
                                // Clear wake matrix entries
                                __cf_word = __cf_i >> 6;
                                __cf_slot_bit = 64'b1 << (__cf_i & 6'h3f);
                                __cf_clear_bits = ~__cf_slot_bit;
                                if (__cf_e.uop.src1_en) begin
                                    __cf_preg8 = __cf_e.uop.src1_preg;
                                    if (__cf_preg8 < 160) begin
                                        __cf_q.wake_matrix_src1[__cf_preg8 * __cf_q.wake_words_per_row + __cf_word] =
                                            __cf_q.wake_matrix_src1[__cf_preg8 * __cf_q.wake_words_per_row + __cf_word] & __cf_clear_bits;
                                    end
                                end
                                if (__cf_e.uop.src2_en) begin
                                    __cf_preg8 = __cf_e.uop.src2_preg;
                                    if (__cf_preg8 < 160) begin
                                        __cf_q.wake_matrix_src2[__cf_preg8 * __cf_q.wake_words_per_row + __cf_word] =
                                            __cf_q.wake_matrix_src2[__cf_preg8 * __cf_q.wake_words_per_row + __cf_word] & __cf_clear_bits;
                                    end
                                end
                                __cf_q.entry_1[__cf_i].valid = 1'b0;
                                __cf_q.count_1 = __cf_q.count_1 - 1;
                            end
                        end
                    end
                end
                iqs[__cf_qi] = __cf_q;
            end
        
            // Flush matching entries from latency_pipe_1
            __cf_surv = 0;
            for (__cf_i = 0; __cf_i < 18; __cf_i++) begin
                __cf_lpe_arr[__cf_i].valid = 1'b0;
                __cf_lpe_arr[__cf_i].countdown = 32'h0;
                __cf_lpe_arr[__cf_i].dest_preg = 32'h0;
                __cf_lpe_arr[__cf_i].br_mask = 64'h0;
                __cf_lpe_arr[__cf_i].rob_idx = 32'h0;
                __cf_lpe_arr[__cf_i].rob_flag = 32'h0;
            end
            for (__cf_i = 0; __cf_i < 18; __cf_i++) begin
                __cf_lpe = latency_pipe_1[__cf_i];
                __cf_match = ((__cf_lpe.br_mask & in_dec_bcast.br_mask) != 64'b0);
                if (!__cf_match) begin
